const COMMON_RELATIVE_FALLBACK = Object.freeze({
  allowedWhen: 'The absolute threshold cannot be judged stably on the current reviewer machine after recording the required environment metadata and preserving raw evidence.',
  requiredImprovementPercentAtLeast: 50,
  comparison: 'candidate p95 or count/rate must be <= 50% of the reviewer-accepted baseline for the same fixture, command, warmup, measured iterations, and environment class',
  requiresAcceptedBaselineArtifact: true,
  acceptedBaselineArtifactMustRecord: Object.freeze([
    'artifact path or immutable report reference',
    'baseline command',
    'baseline fixture profile',
    'warmup/measured iteration counts',
    'environment metadata',
    'metric field path used for comparison',
    'raw p50/p95/count/rate values',
  ]),
  hardInvariantCaveat: 'Relative fallback cannot pass a semantic invariant that says no repeated unchanged-state render, no full-body leak, or no per-member/per-team tmux subprocess fan-out.',
})

const COMMON_RECORDING_RULE = 'Record pass, fail, or blocked per gate in a later release-evidence artifact with raw command output path, env metadata, threshold comparison, fallback comparison if used, exclusions, and reviewer decision; this Slice 3 fixture only defines criteria.'

function gate(input) {
  return Object.freeze({
    id: input.id,
    status: DEFINED_NOT_YET_PROVEN,
    releaseReadyClaim: false,
    scope: input.scope,
    appOwnedTime: input.appOwnedTime,
    metric: input.metric,
    threshold: Object.freeze(input.threshold),
    relativeFallback: COMMON_RELATIVE_FALLBACK,
    fixture: Object.freeze(input.fixture),
    env: COMMON_ENV_METADATA,
    iterations: Object.freeze(input.iterations),
    evidence: Object.freeze(input.evidence),
    exclusions: Object.freeze(input.exclusions),
    passFailRecording: COMMON_RECORDING_RULE,
    stopConditions: Object.freeze([...COMMON_STOP_GATES, ...input.stopConditions]),
  })
}

